                    </tr>\n                    <tr>\n                        <td style=\"padding:0 24px 16px 24px;text-align:center;\">\n                            <div style=\"display:inline-block;background:#f3f4f6;border:1px dashed #cbd5e1;border-radius:10px;padding:18px 24px;font-size:24px;letter-spacing:6px;font-weight:600;color:#111827;\">\n                                218995                            </div>\n                        </td>\n                    </tr>\n                    <tr>\n                        <td style=\"padding:0 24px 16px 24px;font-size:14px;line-height:1.6;color:#4b5563;text-align:center;\">\n                            Kode dan tautan reset berlaku selama <strong>1 jam</strong>.\n                        </td>\n                    </tr>\n                    <tr>\n                        <td style=\"padding:0 24px 24px 24px;text-align:center;\">\n                            <a href=\"https://massipa.test/reset-password?token=fa64efafedc0f7e9ecc680ea0052ece3\" style=\"display:inline-block;background:#5f2eea;color:#ffffff;text-decoration:none;padding:12px 20px;border-radius:10px;font-weight:600;font-size:14px;\">Buka Halaman Reset Password</a>\n                        </td>\n                    </tr>\n                    <tr>\n                        <td style=\"padding:14px 24px 18px 24px;font-size:12px;line-height:1.6;color:#6b7280;text-align:left;\">\n                            Jika Anda tidak mengenali massipa@massipa.xyz, anda dapat mengabaikan email ini dengan aman.\n                        </td>\n                    </tr>\n                    <tr>\n                        <td style=\"padding:0 24px 24px 24px;font-size:13px;color:#9ca3af;text-align:center;\">\n                            © 2026 Pengadilan Tinggi Agama Makassar — MASSIPA\n                        </td>\n                    </tr>\n                </table>\n            </td>\n        </tr>\n    </table>\n</body>\n</html>\n\n', 1, NULL, NULL, 4, NULL, '2026-04-17 